mapper.select:
SELECT t1.ID, t1.SETTLEMENT_NO, t1.MAINT_ORG_ID, t1.MAINT_ORG_NAME, t1.PROJECT_TYPE, t1.TOTAL_BUDGET_AMOUNT, t1.TOTAL_ACTUAL_AMOUNT, t1.APPLY_USER_ID, t1.APPLY_USER_NAME, t1.APPLY_TIME, t1.REMARK, t1.CREATE_BY, t1.CREATE_BY_NAME, t1.CREATE_TIME, t1.UPDATE_BY, t1.UPDATE_BY_NAME, t1.UPDATE_TIME, t3.PROC_INST_ID, (SELECT LISTAGG(s.WORK_ORDER_NO, ',') WITHIN GROUP (ORDER BY s.ID) FROM E_COST_SETTLEMENT_APPLY_SUB s WHERE s.APPLY_ID = t1.ID) AS workOrderNos, CASE WHEN t3.INSTANCE_STATUS IS NULL THEN '0' ELSE t3.INSTANCE_STATUS END AS processStatus, CASE WHEN t2.DICT_LABEL IS NULL THEN '未发起' ELSE t2.DICT_LABEL END AS processStatusLabel FROM E_COST_SETTLEMENT_APPLY t1 LEFT JOIN ( SELECT b.*, ROW_NUMBER() OVER(PARTITION BY BUSINESS_DATA_ID ORDER BY CREATE_TIME DESC, ID DESC) as rn FROM BPM_BUSINESS_INSTANCE b ) t3 ON t3.BUSINESS_DATA_ID = t1.ID AND t3.rn = 1 LEFT JOIN M_DICT_DATA t2 ON t2.DICT_VALUE = t3.INSTANCE_STATUS AND t2.DICT_TYPE = 'APPROVAL_STATUS'
AND t1.SETTLEMENT_NO LIKE #{settlementNoPattern}
AND t1.MAINT_ORG_NAME LIKE #{maintOrgNamePattern}
AND t1.MAINT_ORG_ID = #{maintOrgId}
AND PROJECT_TYPE = #{projectType}
AND APPLY_USER_NAME LIKE #{applyUserNamePattern}
AND EXISTS ( SELECT 1 FROM E_COST_SETTLEMENT_APPLY_SUB s WHERE s.APPLY_ID = t1.ID AND s.WORK_ORDER_NO LIKE #{workOrderNoPattern} )
ORDER BY CREATE_TIME DESC

mapper.delete:
DELETE FROM E_COST_SETTLEMENT_APPLY
WHERE ID IN

    #{id}

mapper.select:
SELECT m.ID, m.WORK_ORDER_NO, m.EQUIP_ID, e.EQUIP_NAME, m.MANT_APP_NUMBER, m.ACCEPTANCE_TIME, m.DISPATCH_TYPE_NAME as dispatchTypeName, a.BUDGET_AMOUNT as budgetAmount FROM E_MAINT_INFO m LEFT JOIN E_M_EQPT_INFO e ON m.EQUIP_ID = e.ID AND e.DEL_FLAG = 0 LEFT JOIN E_IC_MAINT_PROJ_APPLY a ON m.MANT_APP_NUMBER = a.APP_NUMBER
m.STATUS = 5 AND m.DEL_FLAG = 0
AND m.MAINT_ORG_ID = #{maintOrgId}
AND m.DISPATCH_TYPE_NAME = #{projectType}
AND m.WORK_ORDER_NO LIKE #{workOrderNoPattern}
AND e.EQUIP_NAME LIKE #{equipNamePattern}
AND NOT EXISTS ( SELECT 1 FROM E_COST_SETTLEMENT_APPLY_SUB s WHERE s.WORK_ORDER_NO = m.WORK_ORDER_NO AND (s.IS_APPROVAL_REJECT IS NULL OR s.IS_APPROVAL_REJECT != '1')
AND s.APPLY_ID != #{id}
)
ORDER BY m.ACCEPTANCE_TIME DESC
